#!/usr/bin/env bash
# audit-script.tera: Renders a bash audit script for a SourceModule ontology instance.
# Constitutional Equation: audit/<moduleName>.sh = mu(wasm4pm-compat.ttl, SourceModule)
#
# Input variables:
#   moduleName           — snake_case module name, e.g. "ocel"
#   sourceFile           — relative path, e.g. "src/ocel.rs"
#   rustType             — primary Rust type name, e.g. "OcelLog"
#   graduatesToWasm4pm   — boolean, true if this module graduates
#   laws                 — array of law names this module must satisfy
#
# Auto-generated by ggen from wasm4pm-compat.ttl --- DO NOT EDIT
# Source: wasm4pm-compat.ttl  (SourceModule: causal_net)
# Regenerate with: ggen sync --template audit-script.teraset -euo pipefail

REPO_ROOT="$(git rev-parse --show-toplevel)"
PASS_COUNT=0
FAIL_COUNT=0

pass() { echo "PASS  $1"; (( PASS_COUNT += 1 )); }
fail() { echo "FAIL  $1"; (( FAIL_COUNT += 1 )); }

echo "=== Audit: causal_net (causal_net) ==="
echo "    Source: src/causal_net.rs"
echo ""

# -------------------------------------------------------------------------
# CHECK 1: Source module exists
# -------------------------------------------------------------------------
if [[ -f "${REPO_ROOT}/src/causal_net.rs" ]]; then
    pass "module-exists: src/causal_net.rs is present"
else
    fail "module-exists: src/causal_net.rs is MISSING"
fi

# -------------------------------------------------------------------------
# CHECK 2: Module is declared in src/lib.rs (or appropriate root)
# -------------------------------------------------------------------------
if grep -q "mod causal_net" "${REPO_ROOT}/src/lib.rs" 2>/dev/null; then
    pass "module-declared: 'causal_net' found in src/lib.rs"
else
    fail "module-declared: 'causal_net' NOT found in src/lib.rs"
fi

# -------------------------------------------------------------------------
# CHECK 3: At least one compile-pass fixture covers this module
# -------------------------------------------------------------------------
PASS_FIXTURES=$(find "${REPO_ROOT}/tests/ui/compile_pass" -name "*.rs" \
    -exec grep -l "causal_net\|causal_net" {} \; 2>/dev/null | wc -l | tr -d ' ')
if [[ "${PASS_FIXTURES}" -ge 1 ]]; then
    pass "pass-fixture-exists: ${PASS_FIXTURES} compile-pass fixture(s) cover causal_net"
else
    fail "pass-fixture-exists: no compile-pass fixture found for causal_net"
fi

# -------------------------------------------------------------------------
# CHECK 4: At least one compile-fail fixture per declared law
# -------------------------------------------------------------------------


echo "INFO  no laws declared for causal_net — skipping per-law fixture check"


# -------------------------------------------------------------------------
# CHECK 5: Rustdoc present (module-level //! comment)
# -------------------------------------------------------------------------
if grep -q "^//!" "${REPO_ROOT}/src/causal_net.rs" 2>/dev/null; then
    pass "rustdoc-present: //! comment found in src/causal_net.rs"
else
    fail "rustdoc-present: no //! module-level doc in src/causal_net.rs"
fi

# -------------------------------------------------------------------------
# CHECK 6: Graduation marker (if graduatesToWasm4pm)
# -------------------------------------------------------------------------

echo "INFO  causal_net does not graduate to wasm4pm — skipping graduation check"


# -------------------------------------------------------------------------
# CHECK 7: No forbidden patterns
# -------------------------------------------------------------------------
if grep -qE "unsafe\s*\{" "${REPO_ROOT}/src/causal_net.rs" 2>/dev/null; then
    fail "no-unsafe: unsafe block found in src/causal_net.rs — violates #![forbid(unsafe_code)]"
else
    pass "no-unsafe: no unsafe blocks in src/causal_net.rs"
fi

if grep -q "InvalidInput" "${REPO_ROOT}/src/causal_net.rs" 2>/dev/null; then
    fail "no-bare-refusal: 'InvalidInput' found in src/causal_net.rs — refusals must carry named laws"
else
    pass "no-bare-refusal: no bare InvalidInput in src/causal_net.rs"
fi

# -------------------------------------------------------------------------
# SUMMARY
# -------------------------------------------------------------------------
echo ""
echo "=== causal_net audit complete: ${PASS_COUNT} PASS, ${FAIL_COUNT} FAIL ==="

if [[ "${FAIL_COUNT}" -gt 0 ]]; then
    exit 1
fi